import React, { useState, useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function Recommendation() {

    /*const [carbs,setCarbs]=useState(0);
    const [calories,setCalories]=useState(0);*/
    const navigate=useNavigate();
    const [serverData,setServerData]=useState({
        BMI:0,
        total_carbs:0,
        total_calories:0,
        exerciseDuration:0,
        status:{
            BMIStatus:"",
            carbsStatus:"",
            calorieStatus:"",
            exerciseStatus:""
        },
        recommendations:[]
    });

    function goToDashboard(){
        navigate('/dashboard');
    }

    async function handlePage() {
        try{
            const token=localStorage.getItem("token");
            const response=await fetch('http://localhost:5000/recommendation',{
                headers:{
                    Authorization:`Bearer ${token}`
                }
            });
            const data=await response.json();
            console.log(data);
            setServerData(data);
            /*setCalories(data[0].total_calories||0);
            setCarbs(data[0].total_carbs||0)*/
        }
        catch(err){
            console.log(err.message);
        }
    }
            
    useEffect(()=>{handlePage()},[]);

    return (
        <>
            <div className="page-bg">
                <style>{`
                    .page-bg{
                        min-height:100vh;
                        display:flex;
                        align-items:center;
                        justify-content:center;
                        padding:40px;
                        background: linear-gradient(135deg,#e0f7fa 0%, #f3e5f5 100%);
                        font-family: Arial, Helvetica, sans-serif;
                    }
                    .glass-container{
                        width:100%;
                        max-width:820px;
                        background: rgba(255,255,255,0.12);
                        border-radius:16px;
                        padding:28px;
                        box-shadow: 0 8px 32px rgba(31,38,135,0.37);
                        backdrop-filter: blur(8px) saturate(120%);
                        -webkit-backdrop-filter: blur(8px) saturate(120%);
                        border: 1px solid rgba(255,255,255,0.18);
                        color:#05204a;
                    }
                    .glass-header{
                        display:flex;
                        align-items:center;
                        justify-content:space-between;
                        margin-bottom:18px;
                    }
                    .stats{
                        display:grid;
                        grid-template-columns:repeat(auto-fit,minmax(200px,1fr));
                        gap:12px;
                        margin-bottom:16px;
                    }
                    .stat-card{
                        background: rgba(255,255,255,0.06);
                        padding:12px 14px;
                        border-radius:12px;
                        border:1px solid rgba(255,255,255,0.06);
                    }
                    .recommendations{
                        margin:10px 0 18px;
                        padding:12px;
                        border-radius:10px;
                        background: rgba(0,0,0,0.03);
                    }
                    .rec-item{margin:6px 0}
                    .btn{
                        background:linear-gradient(90deg,#6a11cb 0%,#2575fc 100%);
                        color:white;
                        border:none;
                        padding:10px 16px;
                        border-radius:10px;
                        cursor:pointer;
                    }
                `}</style>

                <div className="glass-container">
                    <div className="glass-header">
                        <h2>Health Summary</h2>
                        <div>Exercise: {serverData.exerciseDuration} min</div>
                    </div>

                    <div className="stats">
                        <div className="stat-card"><strong>BMI:</strong> {serverData.BMI}</div>
                        <div className="stat-card"><strong>Carbs:</strong> {serverData.total_carbs}</div>
                        <div className="stat-card"><strong>Ca   lories:</strong> {serverData.total_calories}</div>
                        <div className="stat-card"><strong>BMI Status:</strong> {serverData.status?.BMIStatus}</div>
                        <div className="stat-card"><strong>Carbs Status:</strong> {serverData.status?.carbsStatus}</div>
                        <div className="stat-card"><strong>Calorie Status:</strong> {serverData.status?.calorieStatus}</div>
                        <div className="stat-card"><strong>Exercise Status:</strong> {serverData.status?.exerciseStatus}</div>
                    </div>

                    <div className="recommendations">
                        <h4>Recommendations</h4>
                        {serverData.recommendations?.length ? (
                            serverData.recommendations.map((item,index)=>(<div className="rec-item" key={index}>• {item}</div>))
                        ):(<div className="rec-item">No recommendations available.</div>)}
                    </div>

                    <div style={{textAlign:'right'}}>
                        <button className="btn" onClick={goToDashboard}>Go To Dashboard</button>
                    </div>
                </div>
            </div>
        </>
    )
}

export default Recommendation;
